//! Shared domain validation utilities.

use crate::domain::error::DomainError;

/// GTS type path prefix required for resource group types.
pub const RG_TYPE_PREFIX: &str = "gts.cf.core.rg.type.v1~";

/// Validate a GTS type code: non-empty, correct prefix, length limit.
///
/// Input is normalized (trimmed and lowercased) before validation, consistent
/// with [`resource_group_sdk::models::GtsTypePath::new`].
///
/// # Errors
///
/// Returns [`DomainError`] if the code is empty, missing the required prefix, or exceeds 1024 chars.
// @cpt-algo:cpt-cf-resource-group-algo-sdk-foundation-validate-gts-type-path:p1
// @cpt-algo:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1
pub fn validate_type_code(code: &str) -> Result<(), DomainError> {
    let code = code.trim().to_lowercase();
    let code = code.as_str();
    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-1
    if code.is_empty() {
        return Err(DomainError::validation("Type code must not be empty"));
    }
    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-1
    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2
    if !code.starts_with(RG_TYPE_PREFIX) {
        // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2a
        return Err(DomainError::validation(format!(
            "Type code must start with prefix '{RG_TYPE_PREFIX}', got: '{code}'"
        )));
        // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2a
    }
    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-2
    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-3
    if code.chars().count() > 1024 {
        return Err(DomainError::validation(
            "Type code must not exceed 1024 characters",
        ));
    }
    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-3
    Ok(())
}

/// Validate a membership resource type code: non-empty and length-limited.
///
/// Membership type codes may reference external domain types, so this deliberately
/// does not require [`RG_TYPE_PREFIX`]. Input is normalized for validation the
/// same way as [`validate_type_code`].
///
/// # Errors
///
/// Returns [`DomainError`] if the code is empty or exceeds 1024 chars.
pub fn validate_membership_type_code(code: &str) -> Result<(), DomainError> {
    let code = code.trim().to_lowercase();
    let code = code.as_str();
    if code.is_empty() {
        return Err(DomainError::validation(
            "Membership type code must not be empty",
        ));
    }
    if code.chars().count() > 1024 {
        return Err(DomainError::validation(
            "Membership type code must not exceed 1024 characters",
        ));
    }
    Ok(())
}

/// Validate that a `metadata_schema` value is a valid JSON Schema.
///
/// Attempts to compile the schema via `jsonschema::validator_for`. If the value
/// cannot be interpreted as a JSON Schema, returns a [`DomainError::validation`].
///
/// # Errors
///
/// Returns [`DomainError`] if the value is not a valid JSON Schema.
// @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-7
pub fn validate_metadata_schema(schema: &serde_json::Value) -> Result<(), DomainError> {
    jsonschema::validator_for(schema).map_err(|e| {
        DomainError::validation(format!("metadata_schema is not a valid JSON Schema: {e}"))
    })?;
    Ok(())
}
// @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-7

/// Validate a metadata JSON value against a raw JSON Schema.
///
/// Synchronous counterpart to [`validate_metadata_via_gts`] that does not
/// resolve GTS types. When either `metadata` or `schema` is `None`, the
/// check passes trivially.
///
/// # Errors
///
/// Returns [`DomainError::validation`] when the schema fails to compile
/// or the metadata violates any schema constraint.
pub fn validate_metadata_against_schema(
    metadata: Option<&serde_json::Value>,
    schema: Option<&serde_json::Value>,
) -> Result<(), DomainError> {
    let (Some(metadata), Some(schema)) = (metadata, schema) else {
        return Ok(());
    };

    let validator = jsonschema::validator_for(schema)
        .map_err(|e| DomainError::validation(format!("metadata_schema is invalid: {e}")))?;

    let errors: Vec<String> = validator
        .iter_errors(metadata)
        .map(|e| e.to_string())
        .collect();
    if !errors.is_empty() {
        return Err(DomainError::validation(format!(
            "Metadata does not match type schema: {}",
            errors.join("; ")
        )));
    }
    Ok(())

/// Create a new GTS type definition.
///
/// The full INSERT-junction sequence (`type_repo.insert` →
/// `insert_allowed_parent_types` → `insert_allowed_membership_types` →
/// `load_full_type`) runs inside one `SERIALIZABLE` transaction so that
/// a failure on any step rolls back the whole operation. Without this,
/// a partial insert (e.g. type row written but parent-types junction
/// failed) would leave the registry in an inconsistent state.
pub async fn create_type(
    &self,
    req: CreateTypeRequest,
) -> Result<ResourceGroupType, DomainError> {
    // Pre-validation (pure, no DB) — runs outside the transaction.
    // @cpt-begin:cpt-cf-resource-group-flow-type-mgmt-create-type:p1:inst-create-type-2
    // Validate GTS type path format via `GtsTypePath` value object.
    validation::validate_type_code(&req.code)?;
    // @cpt-end:cpt-cf-resource-group-flow-type-mgmt-create-type:p1:inst-create-type-2
    // @cpt-begin:cpt-cf-resource-group-flow-type-mgmt-create-type:p1:inst-create-type-3
    // Validate placement invariant: `can_be_root OR len(allowed_parent_types) >= 1`.
    Self::validate_placement_invariant(req.can_be_root, &req.allowed_parent_types)?;
    // @cpt-end:cpt-cf-resource-group-flow-type-mgmt-create-type:p1:inst-create-type-3
    if let Some(ref schema) = req.metadata_schema {
        validation::validate_metadata_schema(schema)?;
    }
    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-5
    // FOR EACH parent_path in allowed_parent_types
    for parent_code in &req.allowed_parent_types {
        // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-5a
        // Validate parent_path has RG type prefix `gts.cf.core.rg.type.v1~`
        validation::validate_type_code(parent_code)?;
        // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-5a
    }
    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-5
    // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-6
    // FOR EACH membership_path in allowed_membership_types
    for membership_code in &req.allowed_membership_types {
        // @cpt-begin:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-6a
        // Validate membership_path shape without forcing the RG registry
        // namespace; membership resources may be external domain types.
        validation::validate_membership_type_code(membership_code)?;
        // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-6a
    }
    // @cpt-end:cpt-cf-resource-group-algo-type-mgmt-validate-type-input:p1:inst-val-input-6

    let stored_schema =
        Self::build_stored_schema(req.can_be_root, req.metadata_schema.as_ref());
    let db = self.db.db();
    let type_repo = self.type_repo.clone();

    db.transaction_ref_mapped_with_config(TxConfig::serializable(), |tx| {
        Box::pin(async move {
            // @cpt-begin:cpt-cf-resource-group-flow-type-mgmt-create-type:p1:inst-create-type-8
            // IF unique constraint violation → RETURN TypeAlreadyExists with
            // conflicting schema_id. Performed in-tx so a concurrent create
            // cannot slip a duplicate row in between this read and the
            // insert below.
    code: &str,
    req: UpdateTypeRequest,
) -> Result<ResourceGroupType, DomainError> {
    // Pre-validation (pure, no DB) — runs outside the transaction.
    // @cpt-begin:cpt-cf-resource-group-flow-type-mgmt-update-type:p1:inst-update-type-4
    // Validate placement invariant on new values.
    Self::validate_placement_invariant(req.can_be_root, &req.allowed_parent_types)?;
    // @cpt-end:cpt-cf-resource-group-flow-type-mgmt-update-type:p1:inst-update-type-4
    for parent_code in &req.allowed_parent_types {
        validation::validate_type_code(parent_code)?;
    }
    for membership_code in &req.allowed_membership_types {
        validation::validate_membership_type_code(membership_code)?;
    }
    if let Some(ref schema) = req.metadata_schema {
        validation::validate_metadata_schema(schema)?;
    }

    let stored_schema =
        Self::build_stored_schema(req.can_be_root, req.metadata_schema.as_ref());
    let db = self.db.db();

    assert!(
        matches!(err, DomainError::Validation { .. }),
        "Expected Validation error for missing membership: {err:?}"
    );
}

/// TC-TYP-03b: Create type accepts registered external domain types as allowed memberships.
#[tokio::test]
async fn type_create_accepts_external_allowed_membership_type() {
    let db = common::test_db().await;
    let type_svc = TypeService::new(db.clone(), Arc::new(TypeRepository));
    let external_membership = external_type_code("member");
    seed_type_row(db.as_ref(), &external_membership).await;

    let code = type_code("extmemb");
    let created = type_svc
        .create_type(CreateTypeRequest {
            code: code.clone(),
            can_be_root: true,
            allowed_parent_types: vec![],
            allowed_membership_types: vec![external_membership.clone()],
            metadata_schema: None,
        })
        .await
        .expect("external domain type should be accepted as allowed membership");

    assert_eq!(
        created.allowed_membership_types,
        vec![external_membership.clone()]
    );

    let loaded = type_svc.get_type(&code).await.expect("get created type");
    assert_eq!(loaded.allowed_membership_types, vec![external_membership]);
}

