/// TC-TYP-03d: Create type rejects empty allowed_membership_types entries.
#[tokio::test]
async fn type_create_rejects_empty_allowed_membership_type() {
    let db = common::test_db().await;
    let type_svc = TypeService::new(db.clone(), Arc::new(TypeRepository));

    let err = type_svc
        .create_type(CreateTypeRequest {
            code: type_code("emptymemb"),
            can_be_root: true,
            allowed_parent_types: vec![],
            allowed_membership_types: vec!["  ".to_owned()],
            metadata_schema: None,
        })
        .await
        .expect_err("empty membership code should fail");

    assert!(
        matches!(err, DomainError::Validation { .. }),
        "Expected Validation error for empty membership code: {err:?}"
    );
    assert!(
        err.to_string().contains("must not be empty"),
        "Error should mention empty code: {err:?}"
    );
}

